const raw = $input.first().json;
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const headers = raw.headers || {};

function ve(code, msg) {
  return [{ json: {
    success: false, error_code: code, error_message: msg, data: null,
    _meta: { source: 'SEED_01_Daily_Provisioning', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _exit_early: true
  }}];
}

// P3: Auth check
if (raw.headers && typeof raw.headers === 'object') {
  const token = headers['x-seed-token'] || headers['X-Seed-Token'] || '';
  const expected = $vars?.SEED_AUTH_TOKEN || '';
  if (expected && token !== expected) return ve('AUTH_FAILED', 'Invalid or missing x-seed-token header');
}

// === DATE VALIDATION ===
let date = input.date || new Date().toISOString().split('T')[0];
date = String(date).trim();
const dateParts = date.split('-');
if (dateParts.length !== 3) return ve('INVALID_INPUT', 'date must be YYYY-MM-DD format');
const year = Number(dateParts[0]);
const month = Number(dateParts[1]);
const day = Number(dateParts[2]);
if (isNaN(year) || isNaN(month) || isNaN(day)) return ve('INVALID_INPUT', 'date components must be numeric');
if (year < 1900 || year > 2100) return ve('INVALID_INPUT', 'year must be 1900-2100');
if (month < 1 || month > 12) return ve('INVALID_INPUT', 'month must be 1-12');
const dateObj = new Date(year, month - 1, day);
if (dateObj.getFullYear() !== year || dateObj.getMonth() !== month - 1 || dateObj.getDate() !== day) {
  return ve('INVALID_INPUT', 'date does not exist: ' + date);
}

// === PROVIDER_ID VALIDATION ===
const provider_id = Number(input.provider_id);
if (typeof input.provider_id === 'string' && input.provider_id.trim() === '') return ve('INVALID_INPUT', 'provider_id must be a number');
if (isNaN(provider_id) || !Number.isInteger(provider_id) || provider_id < 1) return ve('INVALID_INPUT', 'provider_id must be a positive integer');

// === SERVICE_ID VALIDATION ===
const service_id = Number(input.service_id);
if (typeof input.service_id === 'string' && input.service_id.trim() === '') return ve('INVALID_INPUT', 'service_id must be a number');
if (isNaN(service_id) || !Number.isInteger(service_id) || service_id < 1) return ve('INVALID_INPUT', 'service_id must be a positive integer');

// === CHAT_ID VALIDATION ===
const chat_id = Number(input.chat_id);
if (typeof input.chat_id === 'string' && input.chat_id.trim() === '') return ve('INVALID_INPUT', 'chat_id must be a number');
if (isNaN(chat_id) || !Number.isInteger(chat_id) || chat_id < 0) return ve('INVALID_INPUT', 'chat_id must be a non-negative integer');

// === HOURS VALIDATION ===
let hours = [9, 10, 11, 12, 13, 14, 15, 16];
if (Array.isArray(input.hours)) {
  if (input.hours.length === 0) return ve('INVALID_INPUT', 'hours array cannot be empty');
  if (input.hours.length > 24) return ve('INVALID_INPUT', 'hours array cannot have more than 24 entries');
  for (let i=0; i<input.hours.length; i++) {
    const hour = Number(input.hours[i]);
    if (isNaN(hour) || !Number.isInteger(hour)) return ve('INVALID_INPUT', 'hour at index ' + i + ' must be an integer');
    if (hour < 0 || hour > 23) return ve('INVALID_INPUT', 'hour must be 0-23');
    hours[i] = hour;
  }
}

// === DURATION_MINUTES VALIDATION ===
const duration_minutes = Number(input.duration_minutes ?? 60);
if (typeof input.duration_minutes === 'string' && input.duration_minutes.trim() === '') return ve('INVALID_INPUT', 'duration_minutes must be a number');
if (isNaN(duration_minutes) || !Number.isInteger(duration_minutes)) return ve('INVALID_INPUT', 'duration_minutes must be an integer');
if (duration_minutes < 15 || duration_minutes > 480) return ve('INVALID_INPUT', 'duration_minutes must be 15-480');

// === TZ_OFFSET VALIDATION ===
let tz_offset = input.tz_offset || '-03:00';
tz_offset = String(tz_offset).trim();
if (tz_offset.length !== 6) return ve('INVALID_INPUT', 'tz_offset must be +HH:MM or -HH:MM');
const tzSign = tz_offset.charAt(0);
if (tzSign !== '+' && tzSign !== '-') return ve('INVALID_INPUT', 'tz_offset must start with + or -');
if (tz_offset.charAt(3) !== ':') return ve('INVALID_INPUT', 'tz_offset must have : at position 4');
const tzHourNum = Number(tz_offset.substring(1, 3));
const tzMinNum = Number(tz_offset.substring(4, 6));
if (isNaN(tzHourNum) || isNaN(tzMinNum)) return ve('INVALID_INPUT', 'tz_offset hours and minutes must be numeric');
if (tzHourNum < 0 || tzHourNum > 14) return ve('INVALID_INPUT', 'tz_offset hours must be 00-14');
if (tzMinNum < 0 || tzMinNum > 59) return ve('INVALID_INPUT', 'tz_offset minutes must be 00-59');

return [{ json: { date, provider_id, service_id, chat_id, hours, duration_minutes, tz_offset, _validated: true } }];

const v = $input.first().json;
if (!v._validated) {
  return [{ json: {
    success: false, error_code: 'PIPELINE_ERROR', error_message: 'unvalidated input reached Generate Slots', data: null,
    _meta: { source: 'SEED_01_Daily_Provisioning', timestamp: new Date().toISOString() },
    _exit_early: true
  }}];
}

const { date, provider_id, service_id, chat_id, hours, duration_minutes, tz_offset } = v;

$execution.customData.set('seed_date', date);
$execution.customData.set('seed_provider', String(provider_id));
$execution.customData.set('seed_service', String(service_id));
$execution.customData.set('seed_slot_count', String(hours.length));

const dateClean = date.replace(/-/g, '');

return hours.map(hour => {
  const h = String(hour).padStart(2, '0');
  const hNext = String(hour + 1).padStart(2, '0');
  const idempotency_key = `SEED-${dateClean}-P${provider_id}-S${service_id}-${h}00`;
  return {
    json: {
      provider_id,
      service_id,
      start_time: `${date}T${h}:00:00${tz_offset}`,
      end_time: `${date}T${hNext}:00:00${tz_offset}`,
      chat_id,
      idempotency_key,
      duration_minutes,
      source: 'SEED_01',
      _slot_generated: true
    }
  };
});

// FIX #8: only onError:continueErrorOutput — no continueOnFail
const err = $input.first().json;
return [{
  json: {
    success: false,
    error_code: 'PROCESS_SLOT_CRASH',
    error_message: err.message || err.error?.message || 'SEED_01_Process_Slot crashed',
    data: { slot: 'unknown', idempotency_key: null, source: 'SEED_01' },
    _meta: { source: 'SEED_01_Daily_Provisioning', timestamp: new Date().toISOString() }
  }
}];

const items = $input.all();
const upstream = $('Validate Input').first()?.json || {};

if (upstream._exit_early) {
  return [{ json: upstream }];
}

let successful = 0;
let duplicates = 0;
let errors = 0;
const details = [];

for (const item of items) {
  const d = item.json;
  if (!d) continue;

  if (d.success === true) {
    if (d.data && d.data.is_duplicate) {
      duplicates++;
    } else {
      successful++;
    }
    details.push({ slot: d.slot || d.data?.booking_id || 'unknown', status: 'success', duplicate: d.data?.is_duplicate || false });
  } else {
    errors++;
    details.push({ slot: d.slot || 'unknown', status: 'error', code: d.error_code, msg: d.error_message });
  }
}

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      date: upstream.date,
      slots_requested: upstream.hours?.length || 0,
      slots_processed: items.length,
      successful,
      duplicates,
      errors,
      details
    },
    _meta: { source: 'SEED_01_Daily_Provisioning', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
  }
}];

// Format Validation Error → Standard Contract
const msg = $input.first()?.json?.message || $input.first()?.json?.error?.message || 'Daily Provisioning validation failed';
return [{
  json: {
    success: false,
    error_code: 'VALIDATION_ERROR',
    error_message: msg,
    data: null,
    _meta: { source: 'SEED_01_Daily_Provisioning', timestamp: new Date().toISOString(), workflow_id: $workflow.id, version: '1.2.0' }
  }
}];

const input = $input.first().json;
if (input._exit_early) return [];
return [{ json: input }];

const input = $input.first().json;
if (!input._exit_early) return [];
return [{ json: input }];
